from dataclasses import dataclass

@dataclass
class State:
    a: int = 0
    b: int = 0
    result: int = 0

def main() -> None:
    state = State()
    initialize(state)
    perform_calculation(state)
    display_result(state)

def initialize(state: State) -> None:
    state.a = 5
    state.b = 10

def perform_calculation(state: State) -> None:
    state.result = state.a + state.b

def display_result(state: State) -> None:
    print(f"Result: {state.result}")

if __name__ == "__main__":
    main()
